    ViewData["Title"] = "Meal Planner Dashboard";
    ViewData["UseWideLayout"] = true;
    ViewData["BodyClass"] = "dashboard-body";

    var dashboardDay = Model.Days
        .FirstOrDefault(day => day.Date.Date == Model.SelectedDate.Date)
        ?? Model.Days.First();

    var breakfastMeal = dashboardDay.Meals.FirstOrDefault(meal => meal.MealType == "Breakfast");
    var lunchMeal = dashboardDay.Meals.FirstOrDefault(meal => meal.MealType == "Lunch");
    var dinnerMeal = dashboardDay.Meals.FirstOrDefault(meal => meal.MealType == "Dinner");
    var snacksMeal = dashboardDay.Meals.Skip(3).FirstOrDefault();
    var dayTargetCalories = Model.DailyNutritionTarget.Calories;
    var macroCalories = (Model.GeneratePlan.ProteinTargetGrams * 4.0)
        + (Model.GeneratePlan.CarbsTargetGrams * 4.0)
        + (Model.GeneratePlan.FatTargetGrams * 9.0);
    var carbShare = macroCalories <= 0 ? 0 : (Model.GeneratePlan.CarbsTargetGrams * 4.0) / macroCalories;
    var fatShare = macroCalories <= 0 ? 0 : (Model.GeneratePlan.FatTargetGrams * 9.0) / macroCalories;
    var initialDietType = carbShare < 0.15 && fatShare > 0.5
        ? "Keto"
        : carbShare > 0.5 && fatShare < 0.3
            ? "Vegan"
            : "Balanced";

